"""Router for Auth — generated by BackendAgent."""
from __future__ import annotations

from fastapi import APIRouter, HTTPException

from schemas import AuthCreate, AuthUpdate, AuthResponse
from services import AuthService

router = APIRouter()
_service = AuthService()


@router.get("/", response_model=list[AuthResponse])
def list_auths() -> list:
    """List all auths."""
    return _service.list_auths()


@router.post("/", response_model=AuthResponse, status_code=201)
def create_auth(data: AuthCreate) -> object:
    """Create a new auth."""
    try:
        return _service.create_auth(data.model_dump())
    except NotImplementedError:
        raise HTTPException(status_code=501, detail="Not yet implemented")


@router.get("/{id}", response_model=AuthResponse)
def get_auth(id: str) -> object:
    """Get a single auth by id."""
    item = _service.get_auth(id)
    if item is None:
        raise HTTPException(status_code=404, detail="Auth not found")
    return item


@router.put("/{id}", response_model=AuthResponse)
def update_auth(id: str, data: AuthUpdate) -> object:
    """Update an existing auth."""
    try:
        result = _service.update_auth(id, data.model_dump(exclude_unset=True))
    except NotImplementedError:
        raise HTTPException(status_code=501, detail="Not yet implemented")
    if result is None:
        raise HTTPException(status_code=404, detail="Auth not found")
    return result


@router.delete("/{id}", status_code=204)
def delete_auth(id: str) -> None:
    """Delete a auth. Level-3 action — requires permission check."""
    if not _service.delete_auth(id):
        raise HTTPException(status_code=404, detail="Auth not found")
